policies.inbound:




			@((string)context.Variables["correlationId"])



			@{  
        var headers = string.Join("\n", context.Request.Headers.Select(h => $"{h.Key}: {string.Join(";", h.Value)}"));  
        var body = context.Request.Body?.As(preserveContent:true) ?? "No Body";  
        return $"correlationId={context.Variables["correlationId"]}\n\nRequest Headers:\n{headers}\n\nRequest Body:\n{body}\n";  
      }






			@{  
        var url = (string)context.Variables["auth_url"];  
        var body = (string)context.Variables["auth_form_body"];  
        return $"correlationId={context.Variables["correlationId"]}\nURL={url}\nMethod=POST\nHeaders:\nContent-Type: application/x-www-form-urlencoded\nCookie: \n\nBody:\n{body}\n";  
      }


			@((string)context.Variables["auth_url"])
			POST

				application/x-www-form-urlencoded


				@((string)context.Variables["correlationId"])

			@((string)context.Variables["auth_form_body"])


			@{  
        var r = (IResponse)context.Variables["respAuth"];  
        var hdr = string.Join("\n", r.Headers.Select(h => $"{h.Key}: {string.Join(";", h.Value)}"));  
        var body = r.Body.As(preserveContent:true);  
        return $"correlationId={context.Variables["correlationId"]}\nStatus={r.StatusCode}\nHeaders:\n{hdr}\n\nBody:\n{body}\n";  
      }


		<set-variable name="access_token" value="@{  
        var r = (IResponse)context.Variables["respAuth"];  
        var jo = r.Body.As(preserveContent:true);  
        return (string)(jo["access_token"] ?? "");  
    }" />



			@{  
        var url = (string)context.Variables["inv_url"];  
        return $"correlationId={context.Variables["correlationId"]}\nURL={url}\nMethod=GET\nHeaders:\nAuthorization: Bearer \nx-correlation-id: {(string)context.Variables["correlationId"]}\n";  
      }


			@((string)context.Variables["inv_url"])
			GET

				@($"Bearer {context.Variables.GetValueOrDefault("access_token")}")


				@((string)context.Variables["correlationId"])



			@{  
        var r = (IResponse)context.Variables["respInv"];  
        var hdr = string.Join("\n", r.Headers.Select(h => $"{h.Key}: {string.Join(";", h.Value)}"));  
        var body = r.Body.As(preserveContent:true);  
        return $"correlationId={context.Variables["correlationId"]}\nStatus={r.StatusCode}\nHeaders:\n{hdr}\n\nBody:\n{body}\n";  
      }


		<set-variable name="openOrder" value="@{  
        var r = (IResponse)context.Variables["respInv"];  
        var s = r.Body.As(preserveContent:true) ?? "";  
        try { return JToken.Parse(s); } catch { return s; }  
    }" />

		<set-variable name="result" value="@{  
    var openOrder = context.Variables.GetValueOrDefault("openOrder") as JToken;  
    if (openOrder == null)  
    {  
        var openOrderStr = context.Variables.GetValueOrDefault("openOrder");  
        try  
        {  
            openOrder = JToken.Parse(openOrderStr);  
        }  
        catch  
        {  
            openOrder = openOrderStr;  
        }  
    }  

    var obj = new JObject  
    {  
        ["correlationId"] = (string)context.Variables["correlationId"],  
        ["openOrder"] = openOrder  
    };  
    return obj;  
}" />

