@{  
        var headers = string.Join("
", context.Response.Headers.Select(h => $"{h.Key}: {string.Join(";", h.Value)}"));  
        var body = context.Response.Body.As(preserveContent:true) ?? "No Body";  
        return $"correlationId={context.Variables["correlationId"]}

Response Headers:
{headers}

Response Body:
{body}
";  
      }
